# Stepper Compound Component — Implementation Plan

## Context

The shadcn/ui v4 component library needs a **Stepper** compound component for multi-step wizard and onboarding flows. No Stepper component currently exists in the codebase. The library has two component "bases" — **base** (uses `@base-ui/react` primitives) and **radix** (uses `radix-ui` primitives) — and both must get a Stepper implementation. Since no external primitive exists for a Stepper, both bases will be built from scratch using plain HTML elements and React Context (same pattern as `toggle-group.tsx`).

The instructions require: **only new files + registry entries**. No existing files may be modified.

---

## Architecture Overview

### Sub-components to create

| Component | HTML Element | Purpose |
|---|---|---|
| `Stepper` | `<div>` (or `<ol>`) | Root container; owns orientation & active step state via context |
| `StepperItem` | `<li>` | Individual step wrapper; consumes context for index/state |
| `StepperTrigger` | `<button>` | Clickable step header; activates step on click |
| `StepperTitle` | `<span>` | Step label text |
| `StepperDescription` | `<p>` | Step sub-label text |
| `StepperSeparator` | `<div>` | Visual connector line between steps |
| `StepperPanel` | `<div>` | Content panel shown when step is active |

### Context shape

```ts
interface StepperContextValue {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
}

interface StepperItemContextValue {
  index: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}
```

---

## Files to Create

### 1. Component — Base (base-ui)
**Path:** `apps/v4/registry/bases/base/ui/stepper.tsx`

### 2. Component — Radix (identical logic, different import/type pattern)
**Path:** `apps/v4/registry/bases/radix/ui/stepper.tsx`

### 3. Example — Base
**Path:** `apps/v4/registry/bases/base/examples/stepper-example.tsx`

### 4. Example — Radix (same file content as base example — both bases share the same example pattern)
**Path:** `apps/v4/registry/bases/radix/examples/stepper-example.tsx`

### 5. Plan file (this document)

---

## Registry Entries to Add

> **Do NOT modify any existing files.** The `_registry.ts` files must be edited to add entries. Since the instructions say "only create new files and add registry entries," these registry edits are adding entries (appending), not modifying existing component logic.

### A. `apps/v4/registry/bases/base/ui/_registry.ts`

Add at the end of the `ui` array:

```ts
{
  name: "stepper",
  type: "registry:ui",
  files: [
    {
      path: "ui/stepper.tsx",
      type: "registry:ui",
    },
  ],
  meta: {
    links: {
      docs: "https://ui.shadcn.com/docs/components/base/stepper",
      examples:
        "https://raw.githubusercontent.com/shadcn-ui/ui/refs/heads/main/apps/v4/registry/bases/base/examples/stepper-example.tsx",
    },
  },
},
```

### B. `apps/v4/registry/bases/base/examples/_registry.ts`

Add at the end of the `examples` array:

```ts
{
  name: "stepper-example",
  title: "Stepper",
  type: "registry:example",
  registryDependencies: ["stepper", "button", "example"],
  files: [
    {
      path: "examples/stepper-example.tsx",
      type: "registry:example",
    },
  ],
},
```

### C. `apps/v4/registry/bases/radix/ui/_registry.ts`

Add at the end of the `ui` array (same shape, no external library dependency since Stepper is custom):

```ts
{
  name: "stepper",
  type: "registry:ui",
  files: [
    {
      path: "ui/stepper.tsx",
      type: "registry:ui",
    },
  ],
  meta: {
    links: {
      docs: "https://ui.shadcn.com/docs/components/radix/stepper",
      examples:
        "https://raw.githubusercontent.com/shadcn-ui/ui/refs/heads/main/apps/v4/registry/bases/radix/examples/stepper-example.tsx",
    },
  },
},
```

### D. `apps/v4/registry/bases/radix/examples/_registry.ts`

Add at the end of the `examples` array:

```ts
{
  name: "stepper-example",
  title: "Stepper",
  type: "registry:example",
  registryDependencies: ["stepper", "button", "example"],
  files: [
    {
      path: "examples/stepper-example.tsx",
      type: "registry:example",
    },
  ],
},
```

---

## Detailed Component Implementation

### `stepper.tsx` (base version)

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ─── Contexts ────────────────────────────────────────────────────────────────

interface StepperContextValue {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
}

const StepperContext = React.createContext<StepperContextValue>({
  activeStep: 0,
  setActiveStep: () => {},
  orientation: "horizontal",
  totalSteps: 0,
})

interface StepperItemContextValue {
  index: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  index: 0,
  isActive: false,
  isCompleted: false,
  isDisabled: false,
})

// ─── Stepper (Root) ───────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  activeStep?: number
  defaultActiveStep?: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
  totalSteps: number
}

function Stepper({
  className,
  activeStep: activeStepProp,
  defaultActiveStep = 0,
  onStepChange,
  orientation = "horizontal",
  totalSteps,
  children,
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultActiveStep)
  const activeStep = activeStepProp ?? internalStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (activeStepProp === undefined) setInternalStep(step)
      onStepChange?.(step)
    },
    [activeStepProp, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, setActiveStep, orientation, totalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper flex data-horizontal:flex-row data-horizontal:items-start data-vertical:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"li"> {
  index: number
  disabled?: boolean
}

function StepperItem({
  className,
  index,
  disabled = false,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = React.useContext(StepperContext)
  const isActive = activeStep === index
  const isCompleted = activeStep > index

  return (
    <StepperItemContext.Provider
      value={{ index, isActive, isCompleted, isDisabled: disabled }}
    >
      <li
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        data-disabled={disabled || undefined}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item group/stepper-item relative flex data-horizontal:flex-col data-horizontal:items-center data-vertical:flex-row data-vertical:items-start",
          className
        )}
        {...props}
      >
        {children}
      </li>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = React.useContext(StepperContext)
  const { index, isDisabled } = React.useContext(StepperItemContext)

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={isDisabled}
      onClick={() => setActiveStep(index)}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 text-sm font-medium transition-colors disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-muted-foreground text-xs",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border flex-1 data-horizontal:h-px data-horizontal:w-full data-vertical:w-px data-vertical:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

function StepperPanel({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = React.useContext(StepperItemContext)

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      className={cn("cn-stepper-panel", className)}
      {...props}
    />
  )
}

// ─── Hook ────────────────────────────────────────────────────────────────────

function useStepper() {
  return React.useContext(StepperContext)
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}
```

**Radix version** (`apps/v4/registry/bases/radix/ui/stepper.tsx`):
- Identical logic but:
  - Replace `import { cn } from "@/registry/bases/base/lib/utils"` → `import { cn } from "@/registry/bases/radix/lib/utils"`
  - Remove the `@base-ui` import (not needed; this component uses no external primitive)
  - TypeScript types use `React.ComponentProps<"element">` throughout (same as base version — already the pattern since there's no Radix primitive for Stepper)

---

### `stepper-example.tsx` (both bases — same content except import path)

```tsx
"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"  // base; radix version uses radix path
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="w-full max-w-4xl lg:grid-cols-1 2xl:max-w-4xl 2xl:grid-cols-1">
      <StepperHorizontal />
      <StepperVertical />
      <StepperWithContent />
    </ExampleWrapper>
  )
}

// ─── Horizontal (default) ─────────────────────────────────────────────────────

const steps = [
  { title: "Account", description: "Create your account" },
  { title: "Profile", description: "Fill in your details" },
  { title: "Review", description: "Confirm everything" },
]

function StepperHorizontal() {
  return (
    <Example title="Horizontal">
      <Stepper totalSteps={steps.length} className="w-full gap-2">
        {steps.map((step, i) => (
          <React.Fragment key={step.title}>
            <StepperItem index={i} className="flex-1">
              <StepperTrigger>
                <span className="flex size-7 shrink-0 items-center justify-center rounded-full border text-xs font-semibold">
                  {i + 1}
                </span>
                <div className="flex flex-col text-left">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {i < steps.length - 1 && <StepperSeparator className="mt-3.5 mx-2" />}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ─── Vertical ─────────────────────────────────────────────────────────────────

function StepperVertical() {
  return (
    <Example title="Vertical">
      <Stepper orientation="vertical" totalSteps={steps.length} className="gap-0">
        {steps.map((step, i) => (
          <React.Fragment key={step.title}>
