  orientation = "horizontal",
  totalSteps,
  children,
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultActiveStep)
  const activeStep = activeStepProp ?? internalStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (activeStepProp === undefined) setInternalStep(step)
      onStepChange?.(step)
    },
    [activeStepProp, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, setActiveStep, orientation, totalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper flex data-horizontal:flex-row data-horizontal:items-start data-vertical:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"li"> {
  index: number
  disabled?: boolean
}

function StepperItem({
  className,
  index,
  disabled = false,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = React.useContext(StepperContext)
  const isActive = activeStep === index
  const isCompleted = activeStep > index

  return (
    <StepperItemContext.Provider
      value={{ index, isActive, isCompleted, isDisabled: disabled }}
    >
      <li
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        data-disabled={disabled || undefined}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item group/stepper-item relative flex data-horizontal:flex-col data-horizontal:items-center data-vertical:flex-row data-vertical:items-start",
          className
        )}
        {...props}
      >
        {children}
      </li>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = React.useContext(StepperContext)
  const { index, isDisabled } = React.useContext(StepperItemContext)

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={isDisabled}
      onClick={() => setActiveStep(index)}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 text-sm font-medium transition-colors disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-muted-foreground text-xs",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border flex-1 data-horizontal:h-px data-horizontal:w-full data-vertical:w-px data-vertical:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

function StepperPanel({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = React.useContext(StepperItemContext)

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      className={cn("cn-stepper-panel", className)}
      {...props}
    />
  )
}

// ─── Hook ────────────────────────────────────────────────────────────────────

function useStepper() {
  return React.useContext(StepperContext)
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}
```

**Radix version** (`apps/v4/registry/bases/radix/ui/stepper.tsx`):
- Identical logic but:
  - Replace `import { cn } from "@/registry/bases/base/lib/utils"` → `import { cn } from "@/registry/bases/radix/lib/utils"`
  - Remove the `@base-ui` import (not needed; this component uses no external primitive)
  - TypeScript types use `React.ComponentProps<"element">` throughout (same as base version — already the pattern since there's no Radix primitive for Stepper)

---

### `stepper-example.tsx` (both bases — same content except import path)

```tsx
"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"  // base; radix version uses radix path
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="w-full max-w-4xl lg:grid-cols-1 2xl:max-w-4xl 2xl:grid-cols-1">
      <StepperHorizontal />
      <StepperVertical />
      <StepperWithContent />
    </ExampleWrapper>
  )
}

// ─── Horizontal (default) ─────────────────────────────────────────────────────

const steps = [
  { title: "Account", description: "Create your account" },
  { title: "Profile", description: "Fill in your details" },
  { title: "Review", description: "Confirm everything" },
]

function StepperHorizontal() {
  return (
    <Example title="Horizontal">
      <Stepper totalSteps={steps.length} className="w-full gap-2">
        {steps.map((step, i) => (
          <React.Fragment key={step.title}>
            <StepperItem index={i} className="flex-1">
              <StepperTrigger>
                <span className="flex size-7 shrink-0 items-center justify-center rounded-full border text-xs font-semibold">
                  {i + 1}
                </span>
                <div className="flex flex-col text-left">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {i < steps.length - 1 && <StepperSeparator className="mt-3.5 mx-2" />}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ─── Vertical ─────────────────────────────────────────────────────────────────

function StepperVertical() {
  return (
    <Example title="Vertical">
      <Stepper orientation="vertical" totalSteps={steps.length} className="gap-0">
        {steps.map((step, i) => (
          <React.Fragment key={step.title}>
            <StepperItem index={i} className="gap-3">
              <StepperTrigger>
                <span className="flex size-7 shrink-0 items-center justify-center rounded-full border text-xs font-semibold">
                  {i + 1}
                </span>
                <div className="flex flex-col text-left">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {i < steps.length - 1 && (
              <StepperSeparator className="ml-3.5 h-6 my-1" />
            )}
          </React.Fragment>
        ))}
      </Stepper>
    </Example>
  )
}

// ─── With Content Panels ──────────────────────────────────────────────────────

const stepsWithContent = [
  {
    title: "Account",
    description: "Create your account",
    content: "Enter your email and set a password to get started.",
  },
  {
    title: "Profile",
    description: "Fill in your details",
    content: "Tell us your name and upload a profile photo.",
  },
  {
    title: "Review",
    description: "Confirm everything",
    content: "Review your information before submitting.",
  },
]

function StepperWithContent() {
  const [active, setActive] = React.useState(0)

  return (
    <Example title="With Content">
      <div className="flex w-full flex-col gap-6">
        <Stepper
          activeStep={active}
          onStepChange={setActive}
          totalSteps={stepsWithContent.length}
          className="w-full gap-2"
        >
          {stepsWithContent.map((step, i) => (
            <React.Fragment key={step.title}>
              <StepperItem index={i} className="flex-1">
                <StepperTrigger>
                  <span className="flex size-7 shrink-0 items-center justify-center rounded-full border text-xs font-semibold">
                    {i + 1}
                  </span>
                  <div className="hidden flex-col text-left sm:flex">
                    <StepperTitle>{step.title}</StepperTitle>
                    <StepperDescription>{step.description}</StepperDescription>
                  </div>
                </StepperTrigger>
                <StepperPanel className="mt-4 text-sm text-muted-foreground">
                  <p>{step.content}</p>
                </StepperPanel>
              </StepperItem>
              {i < stepsWithContent.length - 1 && (
                <StepperSeparator className="mt-3.5 mx-2" />
              )}
            </React.Fragment>
          ))}
        </Stepper>
        <StepperNavigation
          active={active}
          total={stepsWithContent.length}
          onChange={setActive}
        />
      </div>
    </Example>
  )
}

function StepperNavigation({
  active,
  total,
  onChange,
}: {
  active: number
  total: number
  onChange: (step: number) => void
}) {
  return (
    <div className="flex justify-between">
      <Button
        variant="outline"
        disabled={active === 0}
        onClick={() => onChange(active - 1)}
      >
        Previous
      </Button>
      <Button
        disabled={active === total - 1}
        onClick={() => onChange(active + 1)}
      >
        {active === total - 1 ? "Finish" : "Next"}
      </Button>
    </div>
  )
}
```

The **radix version** of the example is identical except for import paths:
- `@/registry/bases/base/...` → `@/registry/bases/radix/...`

---

## Step-by-Step Execution Order

1. **Create** `apps/v4/registry/bases/base/ui/stepper.tsx`
2. **Create** `apps/v4/registry/bases/radix/ui/stepper.tsx` (same logic, different `cn` import path)
3. **Create** `apps/v4/registry/bases/base/examples/stepper-example.tsx`
4. **Create** `apps/v4/registry/bases/radix/examples/stepper-example.tsx` (same content, different import paths)
5. **Edit** `apps/v4/registry/bases/base/ui/_registry.ts` — append `stepper` entry to `ui` array
6. **Edit** `apps/v4/registry/bases/base/examples/_registry.ts` — append `stepper-example` entry to `examples` array
7. **Edit** `apps/v4/registry/bases/radix/ui/_registry.ts` — append `stepper` entry to `ui` array
8. **Edit** `apps/v4/registry/bases/radix/examples/_registry.ts` — append `stepper-example` entry to `examples` array

---

## Key Patterns Observed and Applied

| Pattern | Source | Applied to Stepper |
|---|---|---|
| `"use client"` at top | All interactive components | ✅ Yes (uses `useState`) |
| `data-slot="component-name"` | Every component | ✅ `data-slot="stepper"`, etc. |
| `cn-` class prefix | Every component | ✅ `cn-stepper`, `cn-stepper-item`, etc. |
| `data-orientation` + Tailwind `data-horizontal:` / `data-vertical:` | `tabs.tsx`, `separator.tsx` | ✅ Root sets `data-orientation`; children inherit via CSS |
| `data-active`, `data-completed`, `data-disabled` | Multiple components | ✅ Set on `StepperItem` |
| React Context for shared state | `toggle-group.tsx` | ✅ Two contexts: `StepperContext` + `StepperItemContext` |
| Controlled + uncontrolled pattern | Common React pattern | ✅ `activeStep` prop + `defaultActiveStep` fallback |
| `React.ComponentProps<"element">` | `breadcrumb.tsx`, base components without primitives | ✅ All sub-components |
| `ExampleWrapper` + `Example` | All examples | ✅ Used in demo |
| `useStepper()` hook export | `toggle-group` exports context indirectly | ✅ Exported for advanced use |

---

## Verification

After implementation, verify by:

1. **TypeScript check**: `pnpm tsc --noEmit` from `apps/v4/` — should pass with no errors on new files
2. **Registry build**: `pnpm registry:build` — the new entries should appear in generated indices without errors
3. **Visual check**: Navigate to the stepper component page in the dev app (`pnpm dev`) and confirm:
   - Horizontal layout renders step items in a row with separator lines between them
   - Vertical layout renders step items in a column with separator lines between them
   - Clicking a `StepperTrigger` changes the active step
   - `StepperPanel` content shows/hides based on active step
   - `data-active`, `data-completed`, `data-disabled` attributes are set correctly on items
4. **Registry query**: `shadcn add stepper` resolves the component without errors

