"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ─── Stepper Context ─────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

interface StepperContextValue {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: StepperOrientation
  totalSteps: number
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper>")
  }
  return context
}

// ─── StepperItem Context ─────────────────────────────────────────────────────

interface StepperItemContextValue {
  index: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem>")
  }
  return context
}

// ─── Stepper ─────────────────────────────────────────────────────────────────

interface StepperProps extends Omit<React.ComponentProps<"div">, "onChange"> {
  defaultActiveStep?: number
  activeStep?: number
  onStepChange?: (step: number) => void
  orientation?: StepperOrientation
  totalSteps?: number
}

function Stepper({
  className,
  defaultActiveStep = 0,
  activeStep: activeStepProp,
  onStepChange,
  orientation = "horizontal",
  totalSteps = 0,
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultActiveStep)
  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : internalStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) {
        setInternalStep(step)
      }
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, setActiveStep, orientation, totalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          "data-horizontal:flex-row data-horizontal:items-center",
          "data-vertical:flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: number
  disabled?: boolean
}

function StepperItem({
  className,
  step,
  disabled = false,
  ...props
}: StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step
  const isCompleted = activeStep > step

  return (
    <StepperItemContext.Provider
      value={{ index: step, isActive, isCompleted, isDisabled: disabled }}
    >
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          "group-data-horizontal/stepper:flex-1 group-data-horizontal/stepper:flex-row group-data-horizontal/stepper:items-center",
          "group-data-vertical/stepper:flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { index, isDisabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      disabled={isDisabled}
      onClick={(e) => {
        setActiveStep(index)
        onClick?.(e)
      }}
      className={cn(
        "cn-stepper-trigger flex items-center gap-2 text-left text-sm",
        "disabled:pointer-events-none disabled:opacity-50",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      role="none"
      className={cn(
        "cn-stepper-separator bg-border",
        "group-data-horizontal/stepper:mx-2 group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1",
        "group-data-vertical/stepper:ms-4 group-data-vertical/stepper:mt-1 group-data-vertical/stepper:min-h-4 group-data-vertical/stepper:w-px group-data-vertical/stepper:self-start",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

interface StepperPanelProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperPanel({ className, step, ...props }: StepperPanelProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step

  return (
    <div
      data-slot="stepper-panel"
      hidden={!isActive}
      className={cn("cn-stepper-panel", !isActive && "hidden", className)}
      {...props}
    />
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
  useStepperItem,
}

