// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { index, isDisabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      disabled={isDisabled}
      onClick={(e) => {
        setActiveStep(index)
        onClick?.(e)
      }}
      className={cn(
        "cn-stepper-trigger flex items-center gap-2 text-left text-sm",
        "disabled:pointer-events-none disabled:opacity-50",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      role="none"
      className={cn(
        "cn-stepper-separator bg-border",
        "group-data-horizontal/stepper:mx-2 group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1",
        "group-data-vertical/stepper:ms-4 group-data-vertical/stepper:mt-1 group-data-vertical/stepper:min-h-4 group-data-vertical/stepper:w-px group-data-vertical/stepper:self-start",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

interface StepperPanelProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperPanel({ className, step, ...props }: StepperPanelProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step

  return (
    <div
      data-slot="stepper-panel"
      hidden={!isActive}
      className={cn("cn-stepper-panel", !isActive && "hidden", className)}
      {...props}
    />
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
  useStepperItem,
}

