"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper>
      <StepperHorizontal />
      <StepperVertical />
      <StepperControlled />
    </ExampleWrapper>
  )
}

function StepIndicator({
  step,
  isActive,
  isCompleted,
}: {
  step: number
  isActive: boolean
  isCompleted: boolean
}) {
  return (
    <span
      className={[
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
        isActive
          ? "border-primary bg-primary text-primary-foreground"
          : isCompleted
            ? "border-primary bg-primary text-primary-foreground"
            : "border-muted-foreground/30 text-muted-foreground",
      ].join(" ")}
    >
      {isCompleted ? "✓" : step + 1}
    </span>
  )
}

function StepperHorizontal() {
  return (
    <Example title="Horizontal" containerClassName="col-span-full">
      <Stepper defaultActiveStep={1} orientation="horizontal" className="w-full">
        {[
          { title: "Account", description: "Set up your account" },
          { title: "Profile", description: "Add your details" },
          { title: "Review", description: "Confirm and submit" },
        ].map(({ title, description }, index, arr) => (
          <StepperItem key={title} step={index}>
            <StepperTrigger>
              <span
                className={[
                  "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
                  "group-data-active/stepper-item:border-primary group-data-active/stepper-item:bg-primary group-data-active/stepper-item:text-primary-foreground",
                  "group-data-completed/stepper-item:border-primary group-data-completed/stepper-item:bg-primary group-data-completed/stepper-item:text-primary-foreground",
                  "border-muted-foreground/30 text-muted-foreground",
                ].join(" ")}
              >
                <span className="group-data-completed/stepper-item:hidden">
                  {index + 1}
                </span>
                <span className="hidden group-data-completed/stepper-item:inline">
                  ✓
                </span>
              </span>
              <div className="flex flex-col gap-0.5">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperTrigger>
            {index < arr.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>
    </Example>
  )
}

function StepperVertical() {
  return (
    <Example title="Vertical">
      <Stepper defaultActiveStep={0} orientation="vertical">
        {[
          { title: "Account", description: "Create your account" },
          { title: "Profile", description: "Add your details" },
          { title: "Review", description: "Confirm and submit" },
        ].map(({ title, description }, index, arr) => (
          <StepperItem key={title} step={index}>
            <StepperTrigger>
              <span
                className={[
                  "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
                  "group-data-active/stepper-item:border-primary group-data-active/stepper-item:bg-primary group-data-active/stepper-item:text-primary-foreground",
                  "group-data-completed/stepper-item:border-primary group-data-completed/stepper-item:bg-primary group-data-completed/stepper-item:text-primary-foreground",
                  "border-muted-foreground/30 text-muted-foreground",
                ].join(" ")}
              >
                <span className="group-data-completed/stepper-item:hidden">
                  {index + 1}
                </span>
                <span className="hidden group-data-completed/stepper-item:inline">
                  ✓
                </span>
              </span>
              <div className="flex flex-col gap-0.5">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperTrigger>
            {index < arr.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>
    </Example>
  )
}

const STEPS = [
  {
    title: "Account",
    description: "Create your account",
    content: "Enter your email and password to create your account.",
  },
  {
    title: "Profile",
    description: "Add your details",
    content: "Fill in your name, bio, and profile picture.",
  },
  {
    title: "Review",
    description: "Confirm and submit",
    content: "Review your information and submit to complete setup.",
  },
]

function StepperControlled() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <Example title="Controlled with Navigation" containerClassName="col-span-full">
      <div className="flex w-full flex-col gap-6">
        <Stepper
          activeStep={activeStep}
          onStepChange={setActiveStep}
          orientation="horizontal"
          className="w-full"
        >
          {STEPS.map(({ title, description }, index, arr) => (
            <StepperItem key={title} step={index}>
              <StepperTrigger>
                <span
                  className={[
                    "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
                    "group-data-active/stepper-item:border-primary group-data-active/stepper-item:bg-primary group-data-active/stepper-item:text-primary-foreground",
                    "group-data-completed/stepper-item:border-primary group-data-completed/stepper-item:bg-primary group-data-completed/stepper-item:text-primary-foreground",
                    "border-muted-foreground/30 text-muted-foreground",
                  ].join(" ")}
                >
                  <span className="group-data-completed/stepper-item:hidden">
                    {index + 1}
                  </span>
                  <span className="hidden group-data-completed/stepper-item:inline">
                    ✓
                  </span>
                </span>
                <div className="flex flex-col gap-0.5">
                  <StepperTitle>{title}</StepperTitle>
                  <StepperDescription>{description}</StepperDescription>
                </div>
              </StepperTrigger>
              {index < arr.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </Stepper>

        <div className="rounded-lg border p-6">
          {STEPS.map(({ title, content }, index) => (
            <StepperPanel key={title} step={index}>
              <div className="flex flex-col gap-2">
                <p className="font-medium">{title}</p>
                <p className="text-sm text-muted-foreground">{content}</p>
              </div>
            </StepperPanel>
          ))}
        </div>

        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setActiveStep((s) => Math.max(0, s - 1))}
            disabled={activeStep === 0}
          >
            Previous
          </Button>
          <Button
            onClick={() =>
              setActiveStep((s) => Math.min(STEPS.length - 1, s + 1))
            }
            disabled={activeStep === STEPS.length - 1}
          >
            Next
          </Button>
        </div>
      </div>
    </Example>
  )
}

